INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$e024a65c-0f12-4d42-a017-eba438887766$tag$, $tag$2026010400028$tag$, $tag$Samuel Viana (5583999921166)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"04/01/2026 22:35:13"},{"role":"client","text":"🌟 Boa noite Samuel Viana! Que alegria ter você aqui com a gente! 🙌","time":"04/01/2026 22:35:14"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"04/01/2026 22:35:18"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"04/01/2026 22:35:22"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"04/01/2026 22:35:26"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"04/01/2026 22:35:32"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"04/01/2026 22:35:37"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"04/01/2026 22:35:38"},{"role":"client","text":"Sim, concordo","time":"04/01/2026 22:35:49"},{"role":"client","text":"✅ Obrigado, Samuel Viana! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"04/01/2026 22:35:50"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"04/01/2026 22:35:54"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"04/01/2026 22:36:08"},{"role":"client","text":"Olá! Samuel Viana!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"04/01/2026 22:36:09"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"04/01/2026 22:36:13"},{"role":"client","text":"Falar com um atendente","time":"04/01/2026 22:36:24"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"04/01/2026 22:36:25"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"04/01/2026 22:36:26"},{"role":"client","text":"Ok","time":"04/01/2026 22:36:39"},{"role":"client","text":"Ola","time":"05/01/2026 07:58:35"},{"role":"client","text":"Bom dia","time":"05/01/2026 07:58:36"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"05/01/2026 09:57:33"},{"role":"client","text":"Quais as especialização","time":"05/01/2026 10:04:35"},{"role":"client","text":"Vocês tem","time":"05/01/2026 10:04:35"},{"role":"client","text":"?","time":"05/01/2026 10:04:38"},{"role":"agent","text":"*Thayanne Sales:* Qual o curso que deseja informações ?","time":"05/01/2026 10:05:58","feedba