INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$340f4e5e-c5b2-4a21-acc3-dd2b31aaa608$tag$, $tag$2026010300027$tag$, $tag$Cibs (5583993252135)$tag$, NULL, $tag$Abel Alves$tag$, $tag$[{"role":"client","text":"Ola, tudo bem?","time":"03/01/2026 16:00:01"},{"role":"client","text":"🌟 Boa tarde Cibs! Que alegria ter você aqui com a gente! 🙌","time":"03/01/2026 16:00:02"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"03/01/2026 16:00:05"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"03/01/2026 16:00:09"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"03/01/2026 16:00:13"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"03/01/2026 16:00:19"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"03/01/2026 16:00:25"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"03/01/2026 16:00:26"},{"role":"client","text":"Sim, concordo","time":"03/01/2026 16:01:40"},{"role":"client","text":"✅ Obrigado, Cibs! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"03/01/2026 16:01:41"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"03/01/2026 16:01:45"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"03/01/2026 16:01:54"},{"role":"client","text":"Olá! Cibs!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"03/01/2026 16:01:55"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"03/01/2026 16:02:00"},{"role":"client","text":"Sou aluno e quero ajuda","time":"03/01/2026 16:02:12"},{"role":"client","text":"Claro! Vamos te ajudar o mais rápido possível. Selecione no menu abaixo qual tipo de ajuda você precisa:","time":"03/01/2026 16:02:16"},{"role":"client","text":"Assuntos financeiros","time":"03/01/2026 16:02:36"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"03/01/2026 16:02:36"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"03/01/2026 16:02:37"},{"role":"client","text":"Matrícula da faculdade","time":"03/01/2026 18:22:58"},{"role":"client","text":"Bom dia","time":"05/01/2026 09:22:47"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Abel Alves","time":"05/01/2026 09:59:10"},{"role":"agent","text":"*Abel Alves:* Caro(a) aluno(a),\n\nEstamos vivendo um momento de transição em nosso sistema acadêmico, pois estamos adquirindo um novo Portal do Aluno, que em breve será disponibilizado para todos.\n\nPedimos, gentilmente, que aguarde. Em breve encaminharemos todas as orientações sobre o novo portal.\n\nInformamos que o pagamento referente a este mês será realizado no Portal do Aluno atual. Ainda hoje confirmaremos essa informação e, caso o pagamento seja liberado no portal atual, avisaremos para que você possa realizá-lo normalmente.\n\nAgradecemos a compreensão.\n\nMuito obrigado e Deus abençoe. 🙏","time":"05/01/2026 09:59:16","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ok","time":"05/01/2026 10:08:14"},{"role":"client","text":"Mas o pagamento referente a esse mês será a matrícula?","time":"05/01/2026 10:08:32"},{"role":"agent","text":"*Abel Alves:* Caro aluno, o pagamento será realizado através do seu ATUAL portal do aluno, por favor, me informe seu nome completo para que eu possa liberar o seu pagamento!","time":"05/01/2026 10:34:57","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"?","time":"05/01/2026 10:39:41"},{"role":"client","text":"Da faculdade","time":"05/01/2026 10:39:50"},{"role":"client","text":"Abel Alves transferiu o atendimento para a equipe FICV - COMERCIAL","time":"05/01/2026 10:41:44"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"05/01/2026 11:35:50"},{"role":"client","text":"*Thayanne Sales:* Você já está matriculado em qual curso ?","time":"05/01/2026 11:36:23"},{"role":"client","text":"Bom dia","time":"05/01/2026 11:37:42"},{"role":"client","text":"Direito","time":"05/01/2026 11:37:44"},{"role":"client","text":"Seria o P2 agora","time":"05/01/2026 11:38:11"},{"role":"client","text":"*Thayanne Sales:* O que você paga na rematrícula já é a 1ª mensalidade ","time":"05/01/2026 11:41:05"},{"role":"client","text":"Ok","time":"05/01/2026 11:41:31"},{"role":"client","text":"Vi a mensagem no grupo q vai ser no portal do aluno, vou aguardar","time":"05/01/2026 11:42:01"},{"role":"client","text":"Por favor, quando começam as aulas?","time":"05/01/2026 11:42:11"},{"role":"client","text":"*Thayanne Sales:* 06/02","time":"05/01/2026 11:43:11"},{"role":"client","text":"Muito obrigada ☺️","time":"05/01/2026 11:43:29"},{"role":"client","text":"*Thayanne Sales:* Por nada! Deus abençoe e uma ótima semana","time":"05/01/2026 11:49:01"},{"role":"client","text":"Atendimento Finalizado!\n\nCibs, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"05/01/2026 11:49:08"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"05/01/2026 11:49:09"},{"role":"client","text":"5","time":"05/01/2026 12:00:59"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"05/01/2026 12:01:00"},{"role":"client","text":"Cibs, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"05/01/2026 12:16:00"}]$tag$, $tag$2026-01-03 16:00:01+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$54156408-1410-4e37-866f-d173e300bafa$tag$, $tag$2026010300028$tag$, $tag$Pastora Luciana (5511957144138)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"03/01/2026 16:30:38"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"03/01/2026 16:30:38"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"03/01/2026 16:30:39"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"05/01/2026 09:31:44"},{"role":"agent","text":"*Karina Pimentel:* Olá Bom dia me chamo Karina Pimentel da Cidade Viva! \n","time":"05/01/2026 11:52:10","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom dia","time":"05/01/2026 12:19:37"},{"role":"agent","text":"*Karina Pimentel:* \n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"05/01/2026 13:48:25","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* \n 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"05/01/2026 13:48:47","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"06/01/2026 08:50:44","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nPastora Luciana, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"06/01/2026 08:50:45"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"08/01/2026 12:17:40"},{"role":"client","text":"Sua sessão expirou!","time":"08/01/2026 12:19:41"}]$tag$, $tag$2026-01-03 16:30:38+00$tag$, FALSE, FALSE, 7.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 5, 2, 9, 4, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
