INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$e2cf21a3-89bb-4cd3-93e0-5f83e8c3fe09$tag$, $tag$2026010300038$tag$, $tag$Francisco Aires (5521969191025)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Missiologia Urbana e quero mais informações.","time":"03/01/2026 20:19:05"},{"role":"client","text":"🌟 Boa noite Francisco Aires! Que alegria ter você aqui com a gente! 🙌","time":"03/01/2026 20:19:06"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"03/01/2026 20:19:10"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"03/01/2026 20:19:13"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"03/01/2026 20:19:20"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"03/01/2026 20:19:34"},{"role":"client","text":"Olá! Francisco Aires!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"03/01/2026 20:19:35"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"03/01/2026 20:19:39"},{"role":"client","text":"Saber sobre os cursos","time":"03/01/2026 20:19:50"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"03/01/2026 20:19:54"},{"role":"client","text":"Pós-Graduação","time":"03/01/2026 20:20:05"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"03/01/2026 20:20:09"},{"role":"client","text":"Missiologia Urbana","time":"03/01/2026 20:20:19"},{"role":"client","text":"Aprenda a ler, servir e transformar as cidades com o Evangelho.\n 🏙️ Curso inovador com foco em missão no contexto urbano\n 🎯 Ideal para plantadores de igrejas, missionários e líderes urbanos\n 🕊️ Aulas online com mentoria prática\n","time":"03/01/2026 20:20:20"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"03/01/2026 20:20:24"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"03/01/2026 20:20:38"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"03/01/2026 20:20:38"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"03/01/2026 20:20:40"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"05/01/2026 09:31:55"},{"role":"agent","text":"*Karina Pimentel:* Olá Bom dia me chamo Karina Pimentel da Cidade Viva! \n","time":"05/01/2026 11:57:26","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Oi, Karina!","time":"05/01/2026 12:41:16"},{"role":"client","text":"Gostaria de saber mais informações sobre o curso de Missiologia Aplicada. Eu já havia entrado em contato com a faculdade, mas acabei perdendo as informações aqui no WhatsApp. Então, gostaria de saber sobre isso novamente, por favor.\nAproveitando, tenho uma dúvida: devo concluir a graduação em cerca de dois meses. Queria saber se posso iniciar o curso após o exame ou se o diploma da graduação precisa estar emitido antes do início. Isso seria alguma dificuldade para a faculdade? Ou posso começar mesmo que o diploma seja emitido depois, considerando que a graduação já estará finalizada?","time":"05/01/2026 12:41:20"},{"role":"client","text":"Missiologia urbana***","time":"05/01/2026 12:41:45"},{"role":"agent","text":"*Karina Pimentel:* *Pós-Graduação em Missiologia Urbana*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 360 h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"05/01/2026 16:50:52","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Missiologia Urbana é de 16 parcelas de *359,37*.\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026.","time":"05/01/2026 16:52:35","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nFrancisco Aires, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"06/01/2026 16:10:04"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"06/01/2026 16:10:05"},{"role":"client","text":"Francisco Aires, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"06/01/2026 16:25:05"}]$tag$, $tag$2026-01-03 20:19:05+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 10, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
