INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$09b32c9c-1df0-45ed-a65d-dd686bafe6c6$tag$, $tag$2026010600081$tag$, $tag$Thomas Liberatus (5583993166358)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Direito e quero mais informações.","time":"06/01/2026 13:12:00"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"06/01/2026 13:12:01"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"06/01/2026 13:16:56"},{"role":"agent","text":"*Thayanne Sales:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"06/01/2026 13:17:14","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*   Segue a matriz curricular do curso de Direito *bit.ly/3SpepqX*","time":"06/01/2026 13:17:24","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"06/01/2026 13:17:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"06/01/2026 13:17:36","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Fiz o vestibular","time":"06/01/2026 13:55:58"},{"role":"agent","text":"*Thayanne Sales:* Me envia o seu nome completo","time":"06/01/2026 14:11:27","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Thomaz Alex Pessoa Camelo","time":"06/01/2026 15:05:30"},{"role":"client","text":"Estou preocupado porque a matrícula é até hoje","time":"06/01/2026 15:22:17"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/695d535606a83511850497a3)","time":"06/01/2026 15:24:22","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Oi Entendi. No caso estava tratando da data de inscrição que garanti a mensalidade em 563 conforme relatado acima.","time":"06/01/2026 15:29:09"},{"role":"client","text":"Mas vamos torcer para o sistema voltar","time":"06/01/2026 15:29:35"},{"role":"agent","text":"*Thayanne Sales:* Falei com o T.I e consegui liberar o seu ","time":"06/01/2026 15:36:41","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Agora é só ir no mesmo link que fez a inscrição, na parte \" já me inscrevi\", colocar o seu CPF e na senha é sua data de nascimento completo.\nIr em \"Visualização de contrato\", da o aceite e após isso vai abrir a forma de pagamento.","time":"06/01/2026 15:36:48","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Assim que fizer o pagamento, me envia o comprovante ","time":"06/01/2026 15:37:52","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Estou clicando em visualização de contrato mas não abre","time":"06/01/2026 15:42:11"},{"role":"agent","text":"*Thayanne Sales:* Clica no icone ao lado","time":"06/01/2026 15:57:17","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Deu certo?","time":"06/01/2026 16:01:17","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Agora deu certo","time":"06/01/2026 16:02:37"},{"role":"client","text":"Lerei","time":"06/01/2026 16:02:41"},{"role":"client","text":"Deu certo","time":"06/01/2026 16:20:30"},{"role":"client","text":"Já fiz o pagamento via pix","time":"06/01/2026 16:20:42"},{"role":"client","text":"Arquivo | (https://igrejabatista.widechat.com.br/config/storage/view/695d6091a42227418b043d21)","time":"06/01/2026 16:20:49"},{"role":"agent","text":"*Thayanne Sales:* Que maravilha","time":"06/01/2026 16:22:29","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Seja muito bem-vindo a Faculdade Internacional Cidade Viva ","time":"06/01/2026 16:22:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Agora é só aguardar o inicio das aulas em 06/02","time":"06/01/2026 16:23:02","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"06/01/2026 16:23:10","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Qual a data do início das aulas?","time":"06/01/2026 16:23:11"},{"role":"client","text":"Não. Só isso mesmo e obrigado pela atenção","time":"06/01/2026 16:23:36"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Qualquer dúvida é só chamar.\n\nDeus abençoe e uma ótima semana.","time":"06/01/2026 16:24:26","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nThomas Liberatus, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"06/01/2026 16:24:45"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"09/01/2026 16:21:38"},{"role":"client","text":"Sua sessão expirou!","time":"09/01/2026 16:23:39"}]$tag$, $tag$2026-01-06 13:12:00+00$tag$, FALSE, FALSE, 7.4, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 9, 2, 9, 16, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$ed5d5e0b-864d-41c4-9dbf-e99b288ebbcd$tag$, $tag$2026010600085$tag$, $tag$Lidiane Cardoso (5524999558029)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"oi","time":"06/01/2026 13:30:36"},{"role":"client","text":"🌟 Boa tarde Lidiane Cardoso! Que alegria ter você aqui com a gente! 🙌","time":"06/01/2026 13:30:37"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"06/01/2026 13:30:41"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"06/01/2026 13:30:45"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"06/01/2026 13:30:49"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"06/01/2026 13:30:55"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"06/01/2026 13:31:01"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"06/01/2026 13:31:01"},{"role":"client","text":"Sim, concordo","time":"06/01/2026 13:32:09"},{"role":"client","text":"✅ Obrigado, Lidiane Cardoso! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"06/01/2026 13:32:10"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"06/01/2026 13:32:14"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"06/01/2026 13:32:38"},{"role":"client","text":"Olá! Lidiane Cardoso!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"06/01/2026 13:32:38"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"06/01/2026 13:32:42"},{"role":"client","text":"Falar com um atendente","time":"06/01/2026 13:33:02"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"06/01/2026 13:33:03"},{"role":"client","text":"Pós Graduação em Educação Clássica","time":"06/01/2026 13:33:26"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"06/01/2026 13:50:55"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"06/01/2026 13:51:07","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"06/01/2026 13:51:21","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Oi Karina,  boa tarde","time":"06/01/2026 13:51:26"},{"role":"client","text":"Tudo bem?!","time":"06/01/2026 13:51:32"},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"06/01/2026 13:51:35","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Tudo ótimo e a senhora?","time":"06/01/2026 13:51:51","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Tudo bem tbm graças a Deus","time":"06/01/2026 13:52:55"},{"role":"client","text":"As mensalidades são pagas via cartão?","time":"06/01/2026 13:53:08"},{"role":"client","text":"E serão 16 meses de curso?","time":"06/01/2026 13:53:29"},{"role":"agent","text":"*Karina Pimentel:* Pix, Boleto ou Cartão.","time":"06/01/2026 13:54:25","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Quais materiais e livros são recomendados para serem adquiridos ao longo do curso??","time":"06/01/2026 13:54:26"},{"role":"agent","text":"*Karina Pimentel:* Isso.","time":"06/01/2026 13:54:32","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Já passa o valor integral e vai descontando mensalmente?","time":"06/01/2026 13:54:52"},{"role":"client","text":"Ou pago a primeira agora e depois só em abril?","time":"06/01/2026 13:55:09"},{"role":"client","text":"Como funciona?","time":"06/01/2026 13:55:11"},{"role":"agent","text":"*Karina Pimentel:* Pode pagar mensalmente sem problemas!","time":"06/01/2026 13:55:37","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Vocês enviam link de pagamento?","time":"06/01/2026 13:56:17"},{"role":"agent","text":"*Karina Pimentel:* Os boletos ficarão na Plataforma do aluno para retira-los mensalmente.","time":"06/01/2026 17:11:54","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Entendi","time":"06/01/2026 17:12:26"},{"role":"client","text":"E porque as aulas começam apenas em abril?","time":"06/01/2026 17:12:38"},{"role":"agent","text":"*Karina Pimentel:* Porque será inicio do curso.","time":"06/01/2026 17:16:10","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Não libera o acesso antes!","time":"06/01/2026 17:16:39","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Entendi","time":"06/01/2026 17:20:44"},{"role":"client","text":"Terá alguma aula ao vivo ou todas gravadas?","time":"06/01/2026 17:21:05"},{"role":"client","text":"Bom dia","time":"08/01/2026 07:05:11"},{"role":"client","text":"Pode me confirmar?","time":"08/01/2026 07:20:04"},{"role":"client","text":"Poderia me confirmar tbm sobre os professores?","time":"08/01/2026 07:20:21"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"08/01/2026 08:45:02","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Kari